export function getQuestionsForStep(skills: string[]): QuizQuestion[] {
  const matched: QuizQuestion[] = [];
  const seen = new Set<string>();

  for (const skill of skills) {
    for (const [key, questions] of Object.entries(questionBank)) {
      if (
        skill.toLowerCase().includes(key.toLowerCase()) ||
        key.toLowerCase().includes(skill.toLowerCase())
      ) {
        for (const q of questions) {
          if (!seen.has(q.question)) {
            seen.add(q.question);
            matched.push(q);
          }
        }
      }
    }
  }

  return matched;
}